package com.mengwei.localgrowth.fact;
import com.fasterxml.jackson.databind.ObjectMapper;import com.mengwei.localgrowth.identity.AuthService.Identity;import com.mengwei.localgrowth.shared.ApiExceptionHandler.ApiException;import java.time.OffsetDateTime;import java.util.*;import org.springframework.http.HttpStatus;import org.springframework.jdbc.core.JdbcTemplate;import org.springframework.stereotype.Service;
@Service public class VerifiedFactResolver{private final JdbcTemplate jdbc;private final ObjectMapper json;public VerifiedFactResolver(JdbcTemplate j,ObjectMapper o){jdbc=j;json=o;}
 public Resolved resolve(Identity i,UUID merchant,UUID requested,OffsetDateTime at){var brands=jdbc.queryForList("select id from brand_profiles where tenant_id=? and merchant_id=? and is_primary and not deleted",i.tenantId(),merchant);if(brands.isEmpty())throw bad("FACT_CENTER_NOT_READY","商家尚未建立主品牌");UUID brand=(UUID)brands.getFirst().get("id");var stores=jdbc.queryForList("select id from storefronts where tenant_id=? and merchant_id=? and brand_id=? and not deleted order by is_primary desc",i.tenantId(),merchant,brand);UUID store=requested;if(store==null){if(stores.size()==1)store=(UUID)stores.getFirst().get("id");else if(stores.size()>1)throw bad("STOREFRONT_REQUIRED","该商家有多个门店，请选择门店后生成");}else if(jdbc.queryForList("select id from storefronts where id=? and tenant_id=? and merchant_id=? and brand_id=? and not deleted",store,i.tenantId(),merchant,brand).isEmpty())throw bad("NOT_FOUND","门店不存在或无权访问");var rows=jdbc.queryForList("select f.id fact_id,v.id version_id,f.fact_scope,f.fact_type,v.value_json::text value_json,v.normalized_text,v.effective_from,v.effective_to from merchant_facts f join merchant_fact_versions v on v.id=f.current_version_id and v.tenant_id=f.tenant_id where f.tenant_id=? and f.merchant_id=? and f.brand_id=? and not f.deleted and v.status='VERIFIED' and (v.effective_from is null or v.effective_from<=?) and (v.effective_to is null or v.effective_to>=?) and (f.fact_scope='BRAND' or f.storefront_id=?)",i.tenantId(),merchant,brand,at,at,store);var prohibited=rows.stream().filter(x->"PROHIBITED_CLAIM".equals(x.get("fact_type"))).toList();var positive=rows.stream().filter(x->!"PROHIBITED_CLAIM".equals(x.get("fact_type"))).toList();return new Resolved(merchant,brand,store,positive,prohibited,at);}
 public String snapshot(Resolved r){try{List<Map<String,Object>> facts=r.facts.stream().map(this::map).toList();List<Map<String,Object>> prohib=r.prohibited.stream().map(this::map).toList();return json.writeValueAsString(Map.of("snapshotVersion","fact-center-v1","merchantId",r.merchant,"brandId",r.brand,"storefrontId",r.store,"generatedAt",OffsetDateTime.now().toString(),"effectiveAt",r.at.toString(),"factVersionIds",r.facts.stream().map(x->x.get("version_id").toString()).toList(),"resolvedFacts",facts,"prohibitedClaims",prohib));}catch(Exception e){throw new IllegalStateException(e);}}
 private Map<String,Object> map(Map<String,Object>x){Map<String,Object> result=new LinkedHashMap<>();result.put("factId",x.get("fact_id"));result.put("factVersionId",x.get("version_id"));result.put("factType",x.get("fact_type"));result.put("scope",x.get("fact_scope"));result.put("value",x.get("value_json"));result.put("normalizedText",x.get("normalized_text"));result.put("effectiveFrom",x.get("effective_from"));result.put("effectiveTo",x.get("effective_to"));return result;} private ApiException bad(String c,String m){return new ApiException(HttpStatus.BAD_REQUEST,c,m);}public record Resolved(UUID merchant,UUID brand,UUID store,List<Map<String,Object>> facts,List<Map<String,Object>> prohibited,OffsetDateTime at){}
}
